{"path":"/app/ars.R","old_text":"","new_text":"#' ============================================================================
#' Adaptive Rejection Sampler (ARS)
#' Based on Gilks & Wild (1992): "Adaptive rejection sampling for Gibbs sampling"
#' Journal of the Royal Statistical Society: Series C (Applied Statistics), 41(2), 337-348.
#' ============================================================================

#' ---------------------------------------------------------------------------
#' Module: Input Validation
#' ---------------------------------------------------------------------------

#' Validate inputs to the ars() function.
#' @param logdensity Function computing the log of the (possibly unnormalized) density.
#' @param n Number of samples to draw (positive integer).
#' @param x0 Initial support points (at least 3, within domain).
#' @param domain Numeric vector of length 2: [lower_bound, upper_bound]. Use Inf/-Inf for unbounded.
#' @return NULL (invisibly) if valid; throws error otherwise.
.validate_inputs <- function(logdensity, n, x0, domain) {
  # Check logdensity is a function
  if (!is.function(logdensity)) {
    stop("ars: 'logdensity' must be a function that computes the log-density (possibly unnormalized).")
  }

  # Check n is a positive integer
  if (!is.numeric(n) || length(n) != 1 || n != as.integer(n) || n <= 0) {
    stop("ars: 'n' must be a positive integer.")
  }

  # Check domain
  if (length(domain) != 2) {
    stop("ars: 'domain' must be a numeric vector of length 2 [lower_bound, upper_bound].")
  }
  if (!is.finite(domain[1]) && !is.finite(domain[2])) {
    stop("ars: At least one bound of 'domain' must be finite.")
  }

  # Check x0
  if (length(x0) < 3) {
    stop("ars: 'x0' must contain at least 3 initial support points.")
  }
  if (!is.numeric(x0)) {
    stop("ars: 'x0' must be numeric.")
  }

  # Check x0 are within domain
  for (xi in x0) {
    if (xi <= domain[1] || xi >= domain[2]) {
      stop(sprintf("ars: Support point %.6g is outside the domain (%.6g, %.6g).", xi, domain[1], domain[2]))
    }
  }

  # Check logdensity returns finite values at x0
  y0 <- tryCatch(logdensity(x0), error = function(e) NA_real_)
  if (any(is.na(y0))) {
    stop("ars: 'logdensity' returned NA for some initial support points.")
  }
  if (!all(is.finite(y0))) {
    stop("ars: 'logdensity' returned non-finite values at some initial support points.")
  }

  invisible(NULL)
}


#' ---------------------------------------------------------------------------
#' Module: Log-Concavity Checking
#' ---------------------------------------------------------------------------

#' Check log-concavity of the log-density at a set of points.
#' For log-concavity, the second derivative (discrete approximation via slopes)
#' must be non-increasing. Equivalently, the slopes between consecutive points
#' must be strictly decreasing.
#' @param x Numeric vector of sorted points.
#' @param y Numeric vector of log-density values at x.
#' @return TRUE if log-concave, FALSE otherwise.
.check_log_concavity <- function(x, y) {
  n <- length(x)
  if (n < 3) return(TRUE)

  # Compute slopes between consecutive points
  slopes <- diff(y) / diff(x)

  # For log-concavity, slopes must be strictly decreasing
  slope_diffs <- diff(slopes)

  # Allow small numerical tolerance
  tol <- 1e-8
  if (any(slope_diffs < -tol)) {
    return(FALSE)
  }
  return(TRUE)
}


#' ---------------------------------------------------------------------------
#' Module: Envelope Construction
#' ---------------------------------------------------------------------------

#' Build the piecewise linear/log-linear upper envelope of log(f(x)).
#' The envelope consists of:
#'   - Linear segments between consecutive support points
#'   - Exponential tails on either side (using slopes of first/last segments)
#' @param x Numeric vector of sorted support points.
#' @param y Numeric vector of log-density values at x.
#' @param domain Numeric vector of length 2: [lower_bound, upper_bound].
#' @return List with envelope parameters for sampling.
.build_envelope <- function(x, y, domain) {
  n <- length(x)

  # Compute slopes between consecutive support points
  slopes <- diff(y) / diff(x)

  # Left tail slope (slope of first segment)
  m_left <- slopes[1]
  # Right tail slope (slope of last segment)
  m_right <- slopes[n - 1]

  # Compute areas under each linear segment
  # Area of trapezoid between x[i] and x[i+1]: (y[i] + y[i+1]) * (x[i+1] - x[i]) / 2
  seg_areas <- numeric(n - 1)
  for (i in seq_len(n - 1)) {
    seg_areas[i] <- (y[i] + y[i + 1]) * (x[i + 1] - x[i]) / 2
  }

  # Left tail area: integral from domain[1] to x[1] of exp(linear extrapolation)
  # The linear extrapolation is: y[1] + m_left * (t - x[1])
  # Integral = exp(y[1]) * (x[1] - domain[1]) if m_left == 0
  #           = exp(y[1]) / m_left * (1 - exp(m_left * (domain[1] - x[1]))) otherwise
  # But we need to be careful: the tail is exp(linear), so area = integral of exp(linear)
  if (abs(m_left) < 1e-12) {
    area_left <- exp(y[1]) * (x[1] - domain[1])
  } else {
    # Integral from domain[1] to x[1] of exp(y[1] + m_left*(t - x[1])) dt
    area_left <- exp(y[1]) / m_left * (1 - exp(m_left * (domain[1] - x[1])))
  }

  # Right tail area: integral from x[n] to domain[2] of exp(linear extrapolation)
  if (abs(m_right) < 1e-12) {
    area_right <- exp(y[n]) * (domain[2] - x[n])
  } else {
    # Integral from x[n] to domain[2] of exp(y[n] + m_right*(t - x[n])) dt
    area_right <- exp(y[n]) / (-m_right) * (1 - exp(m_right * (domain[2] - x[n])))
  }

  total_area <- area_left + sum(seg_areas) + area_right

  # Return envelope structure
  list(
    x = x,
    y = y,
    slopes = slopes,
    m_left = m_left,
    m_right = m_right,
    seg_areas = seg_areas,
    area_left = area_left,
    area_right = area_right,
    total_area = total_area,
    domain = domain
  )
}


